import React from "react";
import { useNavigate } from "react-router-dom";

function AdminDashboard() {

  const navigate = useNavigate();

  const logout = () => {
    localStorage.removeItem("adminAuth");
    navigate("/admin/login");
  };

  return (
    <div style={styles.container}>

      <div style={styles.header}>
        <h1>🏛 Admin Dashboard</h1>
        <button onClick={logout} style={styles.logoutBtn}>Logout</button>
      </div>

      <div style={styles.grid}>

        <div style={styles.card}>📋 View Complaints</div>
        <div style={styles.card}>🚨 Emergency Requests</div>
        <div style={styles.card}>💧 Water Service Requests</div>
        <div style={styles.card}>👥 Citizen Records</div>
        <div style={styles.card}>📊 Analytics</div>
        <div style={styles.card}>⚙ System Settings</div>

      </div>

    </div>
  );
}

const styles = {

  container: {
    minHeight: "100vh",
    padding: "20px",
    background: "linear-gradient(135deg,#16222A,#3A6073)",
    color: "#fff"
  },

  header: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center"
  },

  logoutBtn: {
    padding: "8px 15px",
    borderRadius: "8px",
    border: "none",
    background: "#ff4757",
    color: "#fff",
    cursor: "pointer"
  },

  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit,minmax(200px,1fr))",
    gap: "20px",
    marginTop: "30px"
  },

  card: {
    background: "rgba(255,255,255,0.1)",
    padding: "25px",
    borderRadius: "15px",
    textAlign: "center",
    fontWeight: "bold",
    boxShadow: "0 10px 20px rgba(0,0,0,0.4)"
  }

};

export default AdminDashboard;
